INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d0d1b9a2-moex-00115', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', 'X4年初甲公司有面額$10、4%之不可轉換特別股50,000股及面額$10之100,000股普通股發 行流通在外，X4年1月1日甲公司給與員工股票選擇權30,000股，員工於服務滿3年後， 每單位可按每股$30認購普通股一股，給與日每單位員工股票選擇權之公允價值為$18。X5年 7月1日甲公司另發行認股證，股東可按每股$45認購普通股60,000股，至X5年底尚未執 行。甲公司X5年淨利為$740,000，普通股X5年全年平均市價為$48，7月1日至12月31日 之平均市價為$54，則X5年稀釋每股盈餘是多少？', '["$4.65", "$6.13", "$6.19", "$6.40"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00116', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X3年初將存貨計價方法由先進先出法改為加權平均法，各年度期末存貨資料如下： 期末存貨 X1年 X2年 X3年 加權平均法 $300,000 $420,000 $460,000 先進先出法 290,000 380,000 400,000 該項會計政策改變對X3年本期淨利影響為何？', '["減少$20,000", "增加$20,000", "減少$60,000", "增加$60,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00117', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司採行確定福利退休計畫，相關資料如下： X1年12月31日 X2年12月31日 確定福利義務現值 $400,000 $1,000,000 計畫資產公允價值 400,000 1,120,000 已知X2年服務成本為$560,000，X2年計畫資產實際報酬$160,000，X2年底提撥基金$560,000， 折現率10%。若精算師估計X2年淨確定福利資產上限為$80,000，則甲公司X2年確定福利 成本應認列於其他綜合損益之金額為何？', '["損失$40,000", "利得$40,000", "利得$80,000", "利得$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00118', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X4年1月1日將成本$3,000,000，累計折舊$1,000,000之辦公大樓以$1,650,000出 售給乙公司，旋即租回，租期 5 年，每年年底支付租金$300,000。然依照市場行情計算的合 理租金應為每年$400,000，甲公司知道租賃隱含利率為6%，乙公司評估該租賃屬營業租賃。 試問有關甲公司X4年1月1日之會計處理何者正確？ （P5,6%=4.21236；p5,6%=0.74726）', '["認列處分損失$34,944", "認列處分利得$13,286", "認列租賃負債$1,684,944", "認列使用權資產$1,263,708"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00119', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年1月1日購入一部機器設備，成本$700,000，耐用年限7年，殘值$28,000， 採年數合計法提列折舊，後續衡量採成本模式。X3年底該機器設備有減損跡象，估計使用價 值為$288,000，公允價值減處分成本為$272,000，新估計剩餘耐用年限為4年，無殘值，並改 以直線法折舊。若X4年底機器設備之使用價值為$240,000，公允價值減處分成本為$234,000， 則甲公司X4年底應認列減損迴轉利益是多少？', '["$30,000", "$18,000", "$36,000", "$24,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00120', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X4年初為建造廠房向銀行專案借款$8,000,000，期限3年，專案借款利率6%，每 年12月31日支付利息，銀行於X4年1月1日即撥款$8,000,000至甲公司的銀行存款帳戶。 甲公司於X4年1月2日投入工程支出$3,000,000，8月1日再投入工程支出$5,000,000，未動 用之借款資金有存款利息3%。試問甲公司X4年度應資本化之借款成本是多少？', '["$392,500", "$417,500", "$365,000", "$480,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00121', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司將帳面金額$800,000，利率3%之6年期放款組合之所有本金及利息以無追索權方式出 售給乙公司，取得等同於公允價值之現金$824,000。甲公司仍繼續負責向原放款客戶收款後 轉交給乙公司，預期未來將收取之服務成本之現值為$24,000，但提供該服務之足額補償之現 值為$64,000。試問甲公司出售該放款組合應認列之處分損益是多少？', '["損失$16,000", "$0", "利得$24,000", "利得$61,037"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00122', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司以間接法編製現金流量表，X4年相關資料如下：出售交易目的證券投資得款$50,000， 採權益法之長期股權投資收到股利$80,000，購買一部設備付款$250,000，發行公司債 $500,000，支付現金股利$56,000，交易目的證券投資評價利得$9,000。X4 年度折舊費用 $60,000，權益法認列投資收益$120,000，應收帳款淨額減少$66,000，應付帳款增加$58,000， 存貨增加$13,000。若X4年度淨利為$74,000，則甲公司X4年之營業活動現金流量最大可能 金額是多少？', '["流入$24,000", "流入$116,000", "流入$196,000", "流入$246,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00123', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日購入房地產作為營運總部，土地成本$10,000,000，房屋成本 $45,000,000，房屋耐用年限30年，無殘值，採直線法折舊，甲公司對自用不動產採成本模式。 X10年12月31日認列房屋減損損失$6,000,000，耐用年限及殘值估計不變。X11年12月31 日甲公司決定轉換營運總部房地用途，改為按公允價值模式衡量之投資性不動產。X11年12 月31日房屋公允價值$29,000,000，土地之公允價值$18,000,000，則甲公司將自用不動產轉換 為投資性不動產對X11年度其他綜合損益之影響為何？', '["$6,200,000", "$8,000,000", "$8,200,000", "$8,500,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00124', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日開始營業，其X1及X2兩年的稅前會計所得如下： X1年$240,000 X2年$560,000 以下項目導致稅前會計所得和課稅所得之間的差異： ㉑在X1年，公司收到$180,000的3年租金；其中$60,000是在X1年認列為租金收入；其他 $120,000將在X2年至X3年期間平均認列為租金收入。全部$180,000包含在X1年的課稅 所得中。 ㉒公司在X1年和X2年各支付$10,000的污染罰款，該罰款不能在報稅上列報為費用。 ㉓在X2年，公司解雇了一位高階主管，同意支付$90,000遣散費。該金額將於X2年至X4年 每年支付$30,000。全部$90,000在X2年列為費用。就稅務目的而言，當實際支付時遣散費 才可以申報為費用。 X1年12月31日的實施稅率如下： X1 30% X3 40% X2 35% X4 40% 請問X1年與X2年的課稅所得分別為：', '["$370,000;$570,000", "$360,000;$560,000", "$370,000;$510,000", "$250,000;$510,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "fa663c9680b3", "answer_pdf_sha1": "567fe22a3c0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
